SELECT * FROM (
    SELECT
        ,
        ROW_NUMBER() OVER (ORDER BY ${orderColumn} ${orderDir}) AS RN



            AND g.GW_ID LIKE '%' || #{gwId} || '%'


            AND g.GW_NAME LIKE '%' || #{gwName} || '%'


            AND g.IO_TYPE = #{ioType}


)
WHERE RN BETWEEN #{offset} + 1 AND #{offset} + #{limit}
ORDER BY RN



